  obras:  [
    {id:1,codigo:'001',descricao:'Seleme Engenharia',dest:'Seleme Engenharia'},
    {id:2,codigo:'011',descricao:'Figueroa e Cassol Imoveis',dest:'Figueroa e Cassol Imoveis'},
    {id:3,codigo:'223',descricao:'Usifarma S. Filho',dest:'Usifarma S. Filho'}
  ],
  deptos: ['Administrativo','TI','Operacoes','RH','Financeiro','Comercial','Producao','Logistica','Engenharia','Compras'],
  emp: [
    {id:1,nome:'Seleme Engenharia Ltda.',cnpj:'06.260.255/0001-70',ie:'254.773.630',email:'se-xml@seleme.com.br',tel:'(49) 3563-1225',end:'Av. Eng. Lourenco Faoro, 1355, Cacador-SC'},
    {id:2,nome:'Construtora Seleme Ltda',cnpj:'83.218.743/0001-60',ie:'Isento',email:'se-xml@seleme.com.br',tel:'(49) 3563-1225',end:'Rua Conselheiro Mafra, 336, Centro, Cacador-SC'}
  ],
  cc:     JSON.parse(atob(CC_B64)),
  sols:   [],
  ords:   []
