// ---- MODAIS ----
function om(t,h){ document.getElementById('mt').textContent=t; document.getElementById('mb2').innerHTML=h; document.getElementById('mo').style.display='flex'; }
function cm(){ document.getElementById('mo').style.display='none'; }
function gv(id){ var e=document.getElementById(id); return e?e.value.trim():''; }

function mForn(id){
  var f={id:0,razao:'',fantasia:'',cidade:'',uf:'SC',tel:'',cnpj:'',banco:'',ag:'',tipo:'CC',conta:'',obs:''};
  if(id){ var found=DB.forn.find(function(x){ return x.id===id; }); if(found) f=found; }
  om(id?'Editar Fornecedor':'Novo Fornecedor',
    '<div class="fg"><div class="fi"><label>Razao Social *</label><input id="mfr" value="'+esc(f.razao)+'"/></div><div class="fi"><label>Fantasia</label><input id="mff" value="'+esc(f.fantasia)+'"/></div></div>'+
    '<div class="fg"><div class="fi"><label>Cidade</label><input id="mfc" value="'+esc(f.cidade)+'"/></div><div class="fi"><label>UF</label><input id="mfu" value="'+esc(f.uf)+'"/></div></div>'+
    '<div class="fg"><div class="fi"><label>Telefone</label><input id="mft" value="'+esc(f.tel)+'"/></div><div class="fi"><label>CNPJ</label><input id="mfcnpj" value="'+esc(f.cnpj)+'"/></div></div>'+
    '<div class="fg"><div class="fi"><label>Banco</label><input id="mfbn" value="'+esc(f.banco)+'"/></div><div class="fi"><label>Agencia</label><input id="mfag" value="'+esc(f.ag)+'"/></div></div>'+
    '<div class="fg"><div class="fi"><label>Tipo</label><select id="mftp"><option'+(f.tipo==='CC'?' selected':'')+' value="CC">CC</option><option'+(f.tipo==='CP'?' selected':'')+' value="CP">CP</option></select></div><div class="fi"><label>Conta</label><input id="mfct" value="'+esc(f.conta)+'"/></div></div>'+
    '<div class="fg fg1"><div class="fi"><label>Obs/PIX</label><input id="mfob" value="'+esc(f.obs)+'"/></div></div>'+
    '<div class="act"><button class="btn" onclick="cm()">Cancelar</button><button class="btn bp" onclick="svF('+f.id+')">Salvar</button></div>');
}
function svF(id){ var d={razao:gv('mfr'),fantasia:gv('mff'),cidade:gv('mfc'),uf:gv('mfu'),tel:gv('mft'),cnpj:gv('mfcnpj'),banco:gv('mfbn'),ag:gv('mfag'),tipo:gv('mftp'),conta:gv('mfct'),obs:gv('mfob')}; if(!d.razao){alert('Informe a Razao Social.');return;} if(id){var f=DB.forn.find(function(x){return x.id===id;});if(f)Object.assign(f,d);}else DB.forn.push(Object.assign({id:Date.now()},d)); cm();rF();toast('t-ok'); }
function exF(id){ if(confirm('Excluir?')){ DB.forn=DB.forn.filter(function(f){return f.id!==id;});rF(); } }

function mObra(id){
  var o={id:0,codigo:'',descricao:'',dest:''};
  if(id){ var found=DB.obras.find(function(x){ return x.id===id; }); if(found) o=found; }
  om(id?'Editar Obra':'Nova Obra','<div class="fg fg3"><div class="fi"><label>Codigo *</label><input id="moc" value="'+esc(o.codigo)+'"/></div><div class="fi"><label>Descricao *</label><input id="mod" value="'+esc(o.descricao)+'"/></div><div class="fi"><label>Destinatario NF</label><input id="mode" value="'+esc(o.dest)+'"/></div></div><div class="act"><button class="btn" onclick="cm()">Cancelar</button><button class="btn bp" onclick="svO('+o.id+')">Salvar</button></div>');
}
function svO(id){ var d={codigo:gv('moc'),descricao:gv('mod'),dest:gv('mode')}; if(!d.codigo||!d.descricao){alert('Preencha codigo e descricao.');return;} if(id){var o=DB.obras.find(function(x){return x.id===id;});if(o)Object.assign(o,d);}else DB.obras.push(Object.assign({id:Date.now()},d)); cm();rO();toast('t-ok'); }
function exO(id){ if(confirm('Excluir?')){ DB.obras=DB.obras.filter(function(o){return o.id!==id;});rO(); } }

function mDepto(i){
  var val=i>=0?DB.deptos[i]:'';
  om(i>=0?'Editar Departamento':'Novo Departamento','<div class="fi"><label>Nome *</label><input id="mdn" value="'+esc(val)+'"/></div><div class="act"><button class="btn" onclick="cm()">Cancelar</button><button class="btn bp" onclick="svD('+i+')">Salvar</button></div>');
}
function svD(i){ var n=gv('mdn'); if(!n){alert('Informe o nome.');return;} if(i>=0)DB.deptos[i]=n;else DB.deptos.push(n); cm();rD();toast('t-ok'); }
function exD(i){ if(confirm('Excluir?')){ DB.deptos.splice(i,1);rD(); } }

function mEmp(id){
  var e={id:0,nome:'',cnpj:'',ie:'',email:'',tel:'',end:''};
  if(id){ var found=DB.emp.find(function(x){ return x.id===id; }); if(found) e=found; }
  om(id?'Editar Empresa':'Nova Empresa','<div class="fg"><div class="fi"><label>Nome *</label><input id="men" value="'+esc(e.nome)+'"/></div><div class="fi"><label>CNPJ</label><input id="mec" value="'+esc(e.cnpj)+'"/></div></div><div class="fg"><div class="fi"><label>IE</label><input id="mei" value="'+esc(e.ie)+'"/></div><div class="fi"><label>Email NF-e</label><input id="mee" value="'+esc(e.email)+'"/></div></div><div class="fg fg1"><div class="fi"><label>Endereco</label><input id="meen" value="'+esc(e.end)+'"/></div></div><div class="act"><button class="btn" onclick="cm()">Cancelar</button><button class="btn bp" onclick="svE('+e.id+')">Salvar</button></div>');
}
function svE(id){ var d={nome:gv('men'),cnpj:gv('mec'),ie:gv('mei'),email:gv('mee'),end:gv('meen'),tel:''}; if(!d.nome){alert('Informe o nome.');return;} if(id){var e=DB.emp.find(function(x){return x.id===id;});if(e)Object.assign(e,d);}else DB.emp.push(Object.assign({id:Date.now()},d)); cm();rE();toast('t-ok'); }
function exE(id){ if(confirm('Excluir?')){ DB.emp=DB.emp.filter(function(e){return e.id!==id;});rE(); } }

function svPw(nome,elId){ var el=document.getElementById(elId); if(!el||!el.value){alert('Digite a nova senha.');return;} if(el.value.length<4){alert('Minimo 4 caracteres.');return;} APROVADORES[nome].senha=el.value; el.value=''; toast('t-ok'); }

// ---- UTILS ----
function toast(id){ var e=document.getElementById(id); if(!e)return; e.style.display='block'; setTimeout(function(){ e.style.display='none'; },3000); }
function fD(d){ if(!d)return''; if(d.indexOf('/')>=0)return d; var p=d.split('-'); return p[2]+'/'+p[1]+'/'+p[0]; }
function fmt(n){ return(parseFloat(n)||0).toFixed(2).replace('.',',').replace(/\B(?=(\d{3})+(?!\d))/g,'.'); }
function pad4(n){ var s=String(n); while(s.length<4)s='0'+s; return s; }
function esc(s){ return(s||'').replace(/&/g,'&amp;').replace(/"/g,'&quot;').replace(/'/g,'&#39;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); }
